.darma-loader-darma-custom-049 {
  width: 124px;
  height: 24px;
  -webkit-mask:
    conic-gradient(from 135deg at top, #0000, #000 .5deg 90deg, #0000 90.5deg) 0 0,
    conic-gradient(from -45deg at bottom, #0000, #000 .5deg 90deg, #0000 90.5deg) 0 100%;
  -webkit-mask-size: 25% 50%;
  -webkit-mask-repeat: repeat-x;
  background: linear-gradient(var(--loader-color, #25b09b) 0 0) left/0% 100% no-repeat #ddd;
  animation: darma-loader-darma-custom-049-l13 2s infinite linear;
}
@keyframes darma-loader-darma-custom-049-l13 {
  100% { background-size: 100% 100%; }
}

